// AUTO-GENERATED contractCfg.js — regenerated by `npm run build-contractCfg`
// Source of truth: deployed-addresses.json (root) + backend/artifacts/contracts/*.json
// Run this every time you redeploy, change ABI, or wire in a new contract.

const fs = require('fs');
const path = require('path');

const root = path.join(__dirname, '..', '..');  // skellieMonster/
const addressesPath = path.join(root, 'deployed-addresses.json');
const artifactsDir  = path.join(root, 'backend', 'artifacts', 'contracts');
const outputPath    = path.join(__dirname, '..', 'src', 'constant.js');

if (!fs.existsSync(addressesPath)) {
  console.error('[build-contractCfg] MISSING ' + addressesPath);
  console.error('Run `npm run deploy` (from frontend/ or backend/) first.');
  process.exit(1);
}
const addresses = JSON.parse(fs.readFileSync(addressesPath, 'utf8'));

function filterAbi(abi) {
  return (abi || []).filter(x =>
    ['function', 'event', 'constructor', 'error'].includes(x.type)
  );
}

function loadAbi(solFile) {
  const p = path.join(artifactsDir, solFile);
  if (!fs.existsSync(p)) throw new Error('Artifact missing: ' + p);
  return filterAbi(JSON.parse(fs.readFileSync(p, 'utf8')).abi);
}

const tokenABI   = loadAbi('TokenMonster.sol/TokenMonster.json');
const nftABI     = loadAbi('NFTMonster.sol/NFTMonster.json');
const monsterABI = loadAbi('CryptoMonster.sol/CryptoMonster.json');

const out = `// AUTO-GENERATED by scripts/build-contractCfg.js — don't edit by hand
// Regenerate: \`npm run build-contractCfg\`

export const conAddr = {
\ttokenAddr:"${addresses.tokenAddress}",
\tnftAddr:"${addresses.nftAddress}",
\tmonsterAddr:"${addresses.monsterAddress}",
\ttokenABI:${JSON.stringify(tokenABI)},
\tnftABI:${JSON.stringify(nftABI)},
\tmonsterABI:${JSON.stringify(monsterABI)},
};
`;

fs.writeFileSync(outputPath, out);
console.log('[build-contractCfg] wrote', outputPath);
console.log('  token:',   addresses.tokenAddress);
console.log('  nft:',     addresses.nftAddress);
console.log('  monster:', addresses.monsterAddress);
